function solve(s) {
    const n = s.length;
    for (let i = 0; i < n; i++) {
        const j = n - 1 - i;

        // Check if the character at i matches the character at the symmetric position j
        if (s[i] === s[j]) {
            // Since we iterate starting from i=0, the first match found is the minimum index.
            return i;
        }
    }

    // If no such index is found after checking all possibilities
    return -1;
}
